package cn.mtplayer.tv;
import android.content.Context;import android.content.SharedPreferences;import com.google.gson.Gson;import com.google.gson.reflect.TypeToken;import java.lang.reflect.Type;import java.util.ArrayList;import java.util.List;import cn.mtplayer.core.model.MediaItem;
public final class TvLibrary{private static final Type LIST=new TypeToken<List<MediaItem>>(){}.getType();private final SharedPreferences p;private final Gson g=new Gson();public TvLibrary(Context c){p=c.getSharedPreferences("mtplayer.library",Context.MODE_PRIVATE);}public List<MediaItem> favorites(){return read("favorites");}public List<MediaItem> history(){return read("history");}public boolean isFavorite(MediaItem i){return favorites().stream().anyMatch(v->same(v,i));}public void toggle(MediaItem i){List<MediaItem> l=favorites();if(!l.removeIf(v->same(v,i)))l.add(0,i);write("favorites",l);}public void record(MediaItem i){List<MediaItem> l=history();l.removeIf(v->same(v,i));l.add(0,i);while(l.size()>100)l.remove(l.size()-1);write("history",l);}private List<MediaItem> read(String k){List<MediaItem> l=g.fromJson(p.getString(k,"[]"),LIST);return l==null?new ArrayList<>():new ArrayList<>(l);}private void write(String k,List<MediaItem> l){p.edit().putString(k,g.toJson(l)).apply();}private static boolean same(MediaItem a,MediaItem b){return a!=null&&b!=null&&safe(a.siteKey).equals(safe(b.siteKey))&&safe(a.id).equals(safe(b.id));}private static String safe(String s){return s==null?"":s;}}
